SELECT
    COUNT(*) AS TOTAL_PERIZINAN
FROM US_DWH.BI_MART_STATUS_PERIZINAN
WHERE 1 = 1
  AND PERIZINAN IN ('PL', 'PBUMKU', 'PKKPRL', 'PPKH', 'PB')
  AND {tahun}
  AND {bulan}
  AND {perizinan}
  AND {kategori_status}

SELECT
    COUNT(*) AS TOTAL_TERBIT
FROM US_DWH.BI_MART_STATUS_PERIZINAN
WHERE KATEGORI_STATUS = 'Terbit'
  AND PERIZINAN IN ('PL', 'PBUMKU', 'PKKPRL', 'PPKH', 'PB', '31001124', '44441124')
  AND {tahun}
  AND {bulan}
  AND {perizinan}

SELECT
    COUNT(*) AS TOTAL_TOLAK
FROM US_DWH.BI_MART_STATUS_PERIZINAN
WHERE (
    UPPER(KATEGORI_STATUS) LIKE '%TOLAK%' 
    OR UPPER(KATEGORI_STATUS) LIKE '%DITOLAK%' 
    OR UPPER(KATEGORI_STATUS) LIKE '%REJECTED%'
)
  AND PERIZINAN IN ('PL', 'PBUMKU', 'PKKPRL', 'PPKH', 'PB')
  AND {tahun}
  AND {bulan}
  AND {perizinan}

SELECT
    COUNT(*) AS TOTAL_PROSES_PELAKU_USAHA
FROM US_DWH.BI_MART_STATUS_PERIZINAN
WHERE 1 = 1
  AND PERIZINAN IN ('PL', 'PBUMKU', 'PKKPRL', 'PPKH', 'PB')
  AND (
      UPPER(KATEGORI_STATUS) LIKE '%DRAFT%' 
      OR UPPER(KATEGORI_STATUS) LIKE '%PELAKU USAHA%' 
      OR UPPER(KATEGORI_STATUS) LIKE '%WAITING FOR USER%'
  )
  AND {tahun}
  AND {bulan}
  AND {perizinan}
